package controller;
import koneksi.Koneksi;import model.Pengaturan;import java.sql.*;import java.util.*;
public class PengaturanController{public Pengaturan get()throws SQLException{try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT * FROM pengaturan ORDER BY id LIMIT 1");ResultSet r=ps.executeQuery()){return r.next()?new Pengaturan(r.getInt("id"),r.getString("nama_sekolah"),r.getString("alamat"),r.getString("telepon"),r.getString("email"),r.getString("kepala_sekolah"),r.getString("bendahara"),r.getString("logo_path")):new Pengaturan();}}public boolean simpan(Pengaturan p)throws SQLException{String sql="UPDATE pengaturan SET nama_sekolah=?,alamat=?,telepon=?,email=?,kepala_sekolah=?,bendahara=?,logo_path=? WHERE id=?";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql)){ps.setString(1,p.getNamaSekolah());ps.setString(2,p.getAlamat());ps.setString(3,p.getTelepon());ps.setString(4,p.getEmail());ps.setString(5,p.getKepalaSekolah());ps.setString(6,p.getBendahara());ps.setString(7,p.getLogoPath());ps.setInt(8,p.getId());return ps.executeUpdate()>0;}}public List<Object[]> auditLog()throws SQLException{List<Object[]>l=new ArrayList<>();String sql="SELECT a.waktu,u.username,a.aksi,a.tabel_target,a.data_lama,a.data_baru FROM audit_log a LEFT JOIN users u ON u.id=a.user_id ORDER BY a.waktu DESC";try(PreparedStatement ps=Koneksi.getConnection().prepareStatement(sql);ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getTimestamp(1),r.getString(2),r.getString(3),r.getString(4),r.getString(5),r.getString(6)});}return l;}public List<Object[]> users()throws SQLException{List<Object[]>l=new ArrayList<>();try(PreparedStatement ps=Koneksi.getConnection().prepareStatement("SELECT id,nama,username,role,created_at FROM users ORDER BY nama");ResultSet r=ps.executeQuery()){while(r.next())l.add(new Object[]{r.getInt(1),r.getString(2),r.getString(3),r.getString(4),r.getTimestamp(5)});}return l;}}
